export default "        <section id=\"tab-settings\" class=\"tab-pane\">\r\n          <div class=\"panel-header\">\r\n            <h2>⚙️ خيارات التطبيق والجدولة</h2>\r\n            <p class=\"subtitle\">تخصيص الاختصارات وسلوك النطق وتشغيل النظام</p>\r\n          </div>\r\n          <div class=\"settings-workspace\">\r\n            <aside class=\"settings-subnav\" aria-label=\"أقسام الإعدادات\">\r\n              <button class=\"settings-subnav-item active\" data-settings-panel=\"settings-general\">\r\n                <span class=\"settings-subnav-icon\">🌐</span>\r\n                <span class=\"settings-subnav-text\">\r\n                  <strong>الإعدادات العامة</strong>\r\n                  <small>كل الخيارات في صفحة واحدة</small>\r\n                </span>\r\n              </button>\r\n              <button class=\"settings-subnav-item\" data-settings-panel=\"settings-hotkeys\">\r\n                <span class=\"settings-subnav-icon\">⌨️</span>\r\n                <span class=\"settings-subnav-text\">\r\n                  <strong>الاختصارات</strong>\r\n                  <small>مفاتيح التسجيل والأدوات</small>\r\n                </span>\r\n              </button>\r\n              <button class=\"settings-subnav-item\" data-settings-panel=\"settings-tts\">\r\n                <span class=\"settings-subnav-icon\">🔊</span>\r\n                <span class=\"settings-subnav-text\">\r\n                  <strong>النطق</strong>\r\n                  <small>الصوت والسرعة والحجم</small>\r\n                </span>\r\n              </button>\r\n              <button class=\"settings-subnav-item\" data-settings-panel=\"settings-local\">\r\n                <span class=\"settings-subnav-icon\">🤖</span>\r\n                <span class=\"settings-subnav-text\">\r\n                  <strong>النماذج المحلية</strong>\r\n                  <small>خيارات التشغيل دون اتصال</small>\r\n                </span>\r\n              </button>\r\n              <button class=\"settings-subnav-item\" data-settings-panel=\"settings-free-stt\">\r\n                <span class=\"settings-subnav-icon\">🎙️</span>\r\n                <span class=\"settings-subnav-text\">\r\n                  <strong>محركات الصوت</strong>\r\n                  <small>تحويل الصوت إلى نص</small>\r\n                </span>\r\n              </button>\r\n              <button class=\"settings-subnav-item\" data-settings-panel=\"settings-processing\">\r\n                <span class=\"settings-subnav-icon\">⚙️</span>\r\n                <span class=\"settings-subnav-text\">\r\n                  <strong>المعالجة</strong>\r\n                  <small>التشكيل والتصحيح والسلوك</small>\r\n                </span>\r\n              </button>\r\n              <button class=\"settings-subnav-item\" data-settings-panel=\"settings-prompts\">\r\n                <span class=\"settings-subnav-icon\">✍️</span>\r\n                <span class=\"settings-subnav-text\">\r\n                  <strong>البرومبت</strong>\r\n                  <small>توجيهات الذكاء الاصطناعي</small>\r\n                </span>\r\n              </button>\r\n              <button class=\"settings-subnav-item\" data-settings-panel=\"settings-security\">\r\n                <span class=\"settings-subnav-icon\">🔒</span>\r\n                <span class=\"settings-subnav-text\">\r\n                  <strong>النسخ الاحتياطي والأمن</strong>\r\n                  <small>حفظ الإعدادات وتشفير البيانات</small>\r\n                </span>\r\n              </button>\r\n            </aside>\r\n            <div class=\"settings-panel-view\">\r\n          <div class=\"card settings-panel active\" id=\"settings-general\">\r\n            <h3>🌐 إعدادات عامة</h3>\r\n            <p>يعرض هذا القسم عرضاً شاملاً لجميع إعدادات الصفحة دون تخصيص لمجال واحد فقط. يمكنك الوصول إلى الضبط العام لمزيد من التحكم في سلوك التطبيق وسهولة التخصيص.</p>\r\n            <div style=\"display: flex; flex-direction: column; gap: 16px;\">\r\n              <div class=\"info-alert\">\r\n                هذا التبويب يجمع رؤية عامة لجميع الإعدادات المتاحة داخل صفحة الإعدادات، بما في ذلك:\r\n                <ul style=\"margin-top: 10px; padding-inline-start: 20px; color: var(--text-muted); font-size: 13px;\">\r\n                  <li>⌨️ الاختصارات العالمية</li>\r\n                  <li>🔊 إعدادات النطق وصوت القارئ</li>\r\n                  <li>🤖 إعدادات النماذج المحلية</li>\r\n                  <li>🎙️ محركات تحويل الصوت إلى نص</li>\r\n                  <li>⚙️ سلوك معالجة النصوص</li>\r\n                  <li>✍️ تخصيص التوجيهات والبرومبت</li>\r\n                </ul>\r\n              </div>\r\n              <div class=\"card\" style=\"background: rgba(255,255,255,0.03); padding: 16px;\">\r\n                <h4 style=\"margin-bottom: 10px;\">كيف تستخدم هذا التبويب</h4>\r\n                <p style=\"font-size: 13px; color: var(--text-muted); line-height: 1.6;\">\r\n                  هذا القسم مخصّص لعرض الإعدادات العامة في مكان واحد وتسريع التنقل بينها. إذا أردت تعديل إعداد محدد، انتقل إلى التبويب الخاص به أو استعرض المحتوى المباشر في هذه الصفحة.\r\n                </p>\r\n              </div>\r\n            </div>\r\n            <div id=\"settings-general-contents\" class=\"settings-general-contents\" style=\"margin-top: 20px; display: flex; flex-direction: column; gap: 20px;\"></div>\r\n          </div>\r\n          <div class=\"card settings-panel\" id=\"settings-hotkeys\">\r\n            <h3>⌨️ الاختصارات العالمية (Global Hotkeys)</h3>\r\n            <div class=\"info-alert\">تتيح لك هذه الاختصارات تشغيل المساعد في أي وقت بالخلفية. اختر الاختصارات المفضلة لديك ثم اضغط حفظ:</div>\r\n            \r\n            <div style=\"display: flex; flex-direction: column; gap: 20px;\">\r\n              <!-- اختصار تسجيل الصوت -->\r\n              <div class=\"shortcut-editor-box\" style=\"border-bottom: 1px solid var(--border); padding-bottom: 16px;\">\r\n                <label style=\"font-weight: 700; font-size: 13.5px; display: block; margin-bottom: 8px;\">🎙️ اختصار تسجيل الصوت ولصقه:</label>\r\n                <div style=\"display: flex; align-items: center; gap: 12px; flex-wrap: wrap; margin-bottom: 8px;\">\r\n                  <button id=\"btn-record-stt-shortcut\" class=\"shortcut-recorder-btn btn-record-stt-shortcut-class\" title=\"انقر لتعديل هذا الاختصار\" style=\"min-width: 220px; text-align: center; padding: 10px; background: var(--surface-2); border: 1px dashed var(--accent); color: var(--text); border-radius: 8px; font-family: monospace; font-size: 13.5px; cursor: pointer; transition: all 0.2s;\">\r\n                    Ctrl + Shift + 1\r\n                  </button>\r\n                  <button id=\"btn-reset-stt-shortcut\" type=\"button\" class=\"shortcut-reset-btn\" style=\"padding: 8px 10px; font-size: 12px;\">استعادة الافتراضي</button>\r\n                  <span style=\"font-size: 12px; color: var(--text-muted);\">يدعم زرًا واحدًا أو تركيبة من Ctrl / Shift / Alt مع زر آخر</span>\r\n                </div>\r\n                <div style=\"font-size: 12.5px; color: var(--text-muted); margin-bottom: 12px;\">\r\n                  الاختصار النشط حالياً: <strong id=\"lbl-active-stt-shortcut\" class=\"lbl-active-stt-shortcut-class\" style=\"color: #6edcff;\">Ctrl + Shift + 1</strong>\r\n                </div>\r\n                <div style=\"margin-top: 10px;\">\r\n                  <label for=\"select-stt-shortcut-behavior\" style=\"font-weight: 600; font-size: 13px; display: block; margin-bottom: 6px;\">⚙️ سلوك زر اختصار التسجيل:</label>\r\n                  <select id=\"select-stt-shortcut-behavior\" style=\"width: 100%; max-width: 300px; padding: 6px 12px; font-size: 13px; border-radius: 6px; background: var(--surface-2); border: 1px solid var(--border); color: var(--text);\">\r\n                    <option value=\"toggle\">🖱️ بدون سلوك خاص: نقرة واحدة للبدء / الإيقاف</option>\r\n                    <option value=\"hold\">🎙️ ضغط مستمر: يسجل أثناء الضغط فقط</option>\r\n                    <option value=\"double\">⚡ نقرتان: بدء التسجيل، ونقرة للإيقاف</option>\r\n                    <option value=\"long_press_start\">🔘 ضغط مطول: يبدأ بعد الضغط المطول، ونقرة للإيقاف</option>\r\n                  </select>\r\n                </div>\r\n              </div>\r\n\r\n              <!-- اختصار شريط الأدوات -->\r\n              <div class=\"shortcut-editor-box\">\r\n                <label style=\"font-weight: 700; font-size: 13.5px; display: block; margin-bottom: 8px;\">📋 اختصار شريط أدوات النصوص السريعة:</label>\r\n                <div style=\"display: flex; align-items: center; gap: 12px; flex-wrap: wrap; margin-bottom: 8px;\">\r\n                  <button id=\"btn-record-text-shortcut\" class=\"shortcut-recorder-btn btn-record-text-shortcut-class\" title=\"انقر لتعديل هذا الاختصار\" style=\"min-width: 220px; text-align: center; padding: 10px; background: var(--surface-2); border: 1px dashed var(--accent); color: var(--text); border-radius: 8px; font-family: monospace; font-size: 13.5px; cursor: pointer; transition: all 0.2s;\">\r\n                    Ctrl + Shift + 2\r\n                  </button>\r\n                  <button id=\"btn-reset-text-shortcut\" type=\"button\" class=\"shortcut-reset-btn\" style=\"padding: 8px 10px; font-size: 12px;\">استعادة الافتراضي</button>\r\n                  <span style=\"font-size: 12px; color: var(--text-muted);\">يمكن استخدام زر واحد أو تركيبة من زرين أو ثلاثة أو أربعة</span>\r\n                </div>\r\n                <div style=\"font-size: 12.5px; color: var(--text-muted);\">\r\n                  الاختصار النشط حالياً: <strong id=\"lbl-active-text-shortcut\" class=\"lbl-active-text-shortcut-class\" style=\"color: #bc85ff;\">Ctrl + Shift + 2</strong>\r\n                </div>\r\n                <div style=\"margin-top: 10px;\">\r\n                  <label for=\"select-text-shortcut-behavior\" style=\"font-weight: 600; font-size: 13px; display: block; margin-bottom: 6px;\">⚙️ سلوك اختصار شريط الأدوات:</label>\r\n                  <select id=\"select-text-shortcut-behavior\" style=\"width: 100%; max-width: 300px; padding: 6px 12px; font-size: 13px; border-radius: 6px; background: var(--surface-2); border: 1px solid var(--border); color: var(--text);\">\r\n                    <option value=\"single\">🖱️ بدون سلوك خاص: نقرة واحدة لفتح الشريط</option>\r\n                    <option value=\"double\">⚡ نقرتان: فتح الشريط</option>\r\n                    <option value=\"long_press\">🔘 ضغط مطول: فتح الشريط</option>\r\n                    <option value=\"disabled\">🚫 معطّل: إيقاف الاختصار العام وتحرير التركيبة للنظام</option>\r\n                  </select>\r\n                </div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"card settings-panel\" id=\"settings-tts\">\r\n            <h3>🔊 خيارات نطق النصوص (Text-to-Speech)</h3>\r\n            <div class=\"form-group\">\r\n              <label for=\"select-tts-provider\">مزود النطق المفضل:</label>\r\n              <select id=\"select-tts-provider\">\r\n                <option value=\"edge\">Microsoft Edge TTS (سحابي عصبي)</option>\r\n                <option value=\"google\">Google Translate TTS (سحابي)</option>\r\n                <option value=\"sapi5\">Microsoft SAPI5 (محلي بدون إنترنت)</option>\r\n                <option value=\"piper\" disabled>Piper Smart TTS (قريباً ⏳)</option>\r\n              </select>\r\n            </div>\r\n            \r\n            <div class=\"form-group\" style=\"margin-top: 15px;\">\r\n              <label for=\"slider-tts-rate\" style=\"display: flex; justify-content: space-between; font-size: 13px;\">\r\n                <span>🏃 سرعة النطق:</span>\r\n                <strong id=\"display-tts-rate\" style=\"color: var(--accent);\">1.0x</strong>\r\n              </label>\r\n              <input type=\"range\" id=\"slider-tts-rate\" min=\"0.5\" max=\"2.0\" step=\"0.1\" value=\"1.0\" style=\"width: 100%; accent-color: var(--accent); margin-top: 8px;\" />\r\n            </div>\r\n\r\n            <div class=\"form-group\" style=\"margin-top: 15px;\">\r\n              <label for=\"slider-tts-pitch\" style=\"display: flex; justify-content: space-between; font-size: 13px;\">\r\n                <span>🎵 حدة الصوت (النبرة):</span>\r\n                <strong id=\"display-tts-pitch\" style=\"color: var(--accent);\">1.0x</strong>\r\n              </label>\r\n              <input type=\"range\" id=\"slider-tts-pitch\" min=\"0.5\" max=\"2.0\" step=\"0.1\" value=\"1.0\" style=\"width: 100%; accent-color: var(--accent); margin-top: 8px;\" />\r\n            </div>\r\n            \r\n            <div class=\"form-group\" style=\"margin-top: 15px;\">\r\n              <label for=\"slider-tts-volume\" style=\"display: flex; justify-content: space-between; font-size: 13px;\">\r\n                <span>🔊 حجم الصوت:</span>\r\n                <strong id=\"display-tts-volume\" style=\"color: var(--accent);\">100%</strong>\r\n              </label>\r\n              <input type=\"range\" id=\"slider-tts-volume\" min=\"0\" max=\"100\" step=\"5\" value=\"100\" style=\"width: 100%; accent-color: var(--accent); margin-top: 8px;\" />\r\n            </div>\r\n\r\n            <div class=\"form-group\" style=\"margin-top: 15px;\">\r\n              <label for=\"select-tts-voice\">🗣️ اختيار صوت النظام (لقارئ SAPI5):</label>\r\n              <select id=\"select-tts-voice\" style=\"width: 100%; margin-top: 8px;\">\r\n                <option value=\"default\">صوت النظام الافتراضي</option>\r\n              </select>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"card settings-panel\" id=\"settings-local\">\r\n            <h3>🤖 تكامل النماذج المحلية (Local Offline Models)</h3>\r\n            <div class=\"info-alert\">هذه الميزات معطلة حالياً وسيتم تنشيطها في المستقبل عند الحاجة لتوفير تشغيل محلي 100% بدون إنترنت وبخصوصية تامة:</div>\r\n            <div class=\"form-group\">\r\n              <label>نموذج STT محلي (Speech-to-Text):</label>\r\n              <select disabled>\r\n                <option value=\"whisper-local-onnx\">Whisper-Base ONNX (محلي - قريباً ⏳)</option>\r\n                <option value=\"whisper-local-cpp\">Whisper.cpp (محلي - قريباً ⏳)</option>\r\n              </select>\r\n            </div>\r\n            <div class=\"form-group\">\r\n              <label>نموذج ذكاء محلي (LLM):</label>\r\n              <select disabled>\r\n                <option value=\"llama-cpp-local\">Llama 3 8B via llama.cpp (محلي - قريباً ⏳)</option>\r\n                <option value=\"ollama-local\">Ollama Local API (محلي - قريباً ⏳)</option>\r\n              </select>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"card settings-panel\" id=\"settings-free-stt\">\r\n            <h3>🎙️ محركات تحويل الصوت إلى نص المجانية (Free Speech-to-Text)</h3>\r\n            <div class=\"info-alert\">تتيح لك هذه المحركات تحويل الصوت إلى نص مجاناً بالكامل وبدون الحاجة لإدخال أي مفاتيح API مدفوعة:</div>\r\n            <div class=\"form-group\">\r\n              <label for=\"select-free-stt-engine\">المحرك المجاني النشط:</label>\r\n              <select id=\"select-free-stt-engine\">\r\n                <option value=\"none\" selected>-- استخدام نماذج الذكاء الاصطناعي السحابية (Groq / Gemini) --</option>\r\n                <option value=\"google-webspeech\">Google WebSpeech API (سحابي مدمج مجاني بالكامل)</option>\r\n                <option value=\"whisper-cpp-local\" disabled>Whisper.cpp Local Engine (محلي مجاني - قريباً ⏳)</option>\r\n                <option value=\"vosk-local\" disabled>Vosk STT Engine (محلي مجاني - قريباً ⏳)</option>\r\n              </select>\r\n            </div>\r\n            <div id=\"free-stt-status-msg\" style=\"font-size: 12px; color: var(--text-muted); margin-top: 8px; line-height: 1.4; display: none;\">\r\n              ℹ️ عند تفعيل المحرك المجاني، سيتم استخدامه مباشرة للتسجيل بدلاً من خوادم الذكاء الاصطناعي المحددة في التبويبات الأخرى.\r\n            </div>\r\n            <div class=\"checkbox-group\" style=\"margin-top: 12px;\">\r\n              <label>\r\n                <input type=\"checkbox\" id=\"chk-live-transcription\" />\r\n                تفعيل التدوين المباشر أثناء الاستماع (إظهار النص فور نطقه قبل إيقاف التسجيل)\r\n              </label>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"card settings-panel\" id=\"settings-processing\">\r\n            <h3>⚙️ التشغيل وسلوك معالجة النصوص</h3>\r\n            <div style=\"display: flex; flex-direction: column; gap: 14px;\">\r\n              <div class=\"checkbox-group\">\r\n                <label style=\"display: flex; align-items: center; gap: 8px; font-weight: 600; font-size: 13.5px; cursor: pointer;\">\r\n                  <input type=\"checkbox\" id=\"chk-background-recording\" style=\"cursor: pointer;\" />\r\n                  🤫 تفعيل وضع التسجيل الصامت في الخلفية (بدون إظهار نافذة التطبيق)\r\n                </label>\r\n              </div>\r\n              <div class=\"checkbox-group\">\r\n                <label>\r\n                  <input type=\"checkbox\" id=\"chk-simulate-typing\" />\r\n                  محاكاة كتابة الحروف حرفاً بحرف (بدلاً من اللصق السريع عبر الحافظة)\r\n                </label>\r\n              </div>\r\n              <div class=\"form-group\" style=\"margin: 0;\">\r\n                <label for=\"select-output-target\" style=\"font-weight: 700; font-size: 13px;\">وجهة النص بعد التحويل:</label>\r\n                <select id=\"select-output-target\" style=\"margin-top: 6px;\">\r\n                  <option value=\"both\">صندوق التطبيق والنافذة النشطة الخارجية معاً</option>\r\n                  <option value=\"external\">النافذة النشطة الخارجية فقط</option>\r\n                  <option value=\"app\">صندوق التطبيق فقط</option>\r\n                </select>\r\n              </div>\r\n              <div class=\"checkbox-group\">\r\n                <label>\r\n                  <input type=\"checkbox\" id=\"chk-selection-floating-menu\" />\r\n                  إظهار شريط إجراءات النصوص السريعة تلقائياً عند تظليل النص داخل التطبيق أو خارجه\r\n                </label>\r\n              </div>\r\n              <div class=\"checkbox-group\">\r\n                <label>\r\n                  <input type=\"checkbox\" id=\"chk-settings-auto-diacritize\" />\r\n                  تشكيل النصوص العربية تلقائياً بالحركات فور استخلاصها من الصوت\r\n                </label>\r\n              </div>\r\n              <div class=\"checkbox-group\">\r\n                <label>\r\n                  <input type=\"checkbox\" id=\"chk-settings-auto-grammar\" />\r\n                  تدقيق وتصحيح النصوص إملائياً ولغوياً تلقائياً بعد التسجيل (لكافة اللغات)\r\n                </label>\r\n              </div>\r\n              <div class=\"checkbox-group\">\r\n                <label>\r\n                  <input type=\"checkbox\" id=\"chk-settings-voice-translation\" />\r\n                  ترجمة النصوص المستخلصة من الصوت تلقائياً للغة المستهدفة ونطقها صوتياً فوراً ( Voice Translation )\r\n                </label>\r\n              </div>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"card settings-panel\" id=\"settings-prompts\">\r\n            <h3>✍️ تخصيص البرومبت والتوجيهات (Prompt Customization)</h3>\r\n            <div class=\"info-alert\">تتيح لك هذه الإعدادات التحكم في توجيهات (Prompts) الذكاء الاصطناعي لتخصيص سلوك المعالجة والتشكيل:</div>\r\n            \r\n            <div class=\"form-group\" style=\"margin-top: 15px;\">\r\n              <label for=\"textarea-prompt-diacritize\" style=\"font-weight: 700; font-size: 13px;\">✏️ توجيه التشكيل التلقائي (Diacritization Prompt):</label>\r\n              <textarea id=\"textarea-prompt-diacritize\" style=\"height: 60px; font-size: 12.5px; margin-top: 6px; width: 100%; box-sizing: border-box; padding: 8px;\" placeholder=\"أدخل توجيه التشكيل هنا...\"></textarea>\r\n            </div>\r\n\r\n            <div class=\"form-group\" style=\"margin-top: 15px;\">\r\n              <label for=\"textarea-prompt-grammar\" style=\"font-weight: 700; font-size: 13px;\">✍️ توجيه التدقيق الإملائي والنحوي (Grammar Correction Prompt):</label>\r\n              <textarea id=\"textarea-prompt-grammar\" style=\"height: 60px; font-size: 12.5px; margin-top: 6px; width: 100%; box-sizing: border-box; padding: 8px;\" placeholder=\"أدخل توجيه التدقيق هنا...\"></textarea>\r\n            </div>\r\n\r\n            <div class=\"form-group\" style=\"margin-top: 15px;\">\r\n              <label for=\"textarea-prompt-translate\" style=\"font-weight: 700; font-size: 13px;\">🌐 توجيه الترجمة الفورية (Translation Prompt):</label>\r\n              <textarea id=\"textarea-prompt-translate\" style=\"height: 60px; font-size: 12.5px; margin-top: 6px; width: 100%; box-sizing: border-box; padding: 8px;\" placeholder=\"أدخل توجيه الترجمة هنا...\"></textarea>\r\n            </div>\r\n\r\n            <div class=\"form-group\" style=\"margin-top: 15px;\">\r\n              <label for=\"textarea-prompt-summarize\" style=\"font-weight: 700; font-size: 13px;\">📝 توجيه التلخيص (Summarization Prompt):</label>\r\n              <textarea id=\"textarea-prompt-summarize\" style=\"height: 60px; font-size: 12.5px; margin-top: 6px; width: 100%; box-sizing: border-box; padding: 8px;\" placeholder=\"أدخل توجيه التلخيص هنا...\"></textarea>\r\n            </div>\r\n\r\n            <button id=\"btn-reset-prompts\" style=\"margin-top: 15px; background: rgba(255, 255, 255, 0.05); border: 1px solid var(--border); color: var(--text); width: 100%; padding: 10px; border-radius: 6px; cursor: pointer; font-size: 12.5px; transition: all 0.2s;\">🔄 استعادة التوجيهات الافتراضية</button>\r\n          </div>\r\n          \r\n          <div class=\"card settings-panel\" id=\"settings-security\">\r\n            <h3>🔒 النسخ الاحتياطي والنسخ المشفر</h3>\r\n            <div class=\"info-alert\">يمكنك تصدير كافة الإعدادات والبيانات والمفاتيح بشكل مشفر وآمن بكلمة مرور، أو استيرادها لاستعادتها لاحقاً:</div>\r\n            \r\n            <div style=\"display: flex; flex-direction: column; gap: 20px;\">\r\n              <!-- تصدير النسخة الاحتياطية -->\r\n              <div class=\"card\" style=\"background: rgba(255,255,255,0.02); padding: 16px; border: 1px solid var(--border); border-radius: 8px;\">\r\n                <h4 style=\"margin-bottom: 8px; display: flex; align-items: center; gap: 8px;\">📤 تصدير نسخة احتياطية مشفرة</h4>\r\n                <p style=\"font-size: 12.5px; color: var(--text-muted); margin-bottom: 12px;\">سيتم تشفير كامل إعداداتك ومفاتيح الـ API المدخلة باستخدام خوارزمية AES-256-GCM بكلمة المرور المحددة.</p>\r\n                <div style=\"display: flex; flex-direction: column; gap: 10px;\">\r\n                  <input type=\"password\" id=\"input-backup-export-password\" placeholder=\"أدخل كلمة مرور لتشفير النسخة الاحتياطية...\" style=\"width: 100%; padding: 8px 12px; font-size: 13px; border-radius: 6px; background: var(--surface-2); border: 1px solid var(--border); color: var(--text);\" />\r\n                  <button id=\"btn-export-backup\" class=\"btn-activate-key\" style=\"width: 100%; padding: 10px; font-weight: bold; background: var(--accent); color: white;\">تصدير وحفظ الملف...</button>\r\n                </div>\r\n              </div>\r\n\r\n              <!-- استيراد النسخة الاحتياطية -->\r\n              <div class=\"card\" style=\"background: rgba(255,255,255,0.02); padding: 16px; border: 1px solid var(--border); border-radius: 8px;\">\r\n                <h4 style=\"margin-bottom: 8px; display: flex; align-items: center; gap: 8px;\">📥 استيراد نسخة احتياطية</h4>\r\n                <p style=\"font-size: 12.5px; color: var(--text-muted); margin-bottom: 12px;\">اختر ملف النسخة الاحتياطية المشفر وأدخل كلمة المرور لفك التشفير واستعادة كامل بياناتك.</p>\r\n                <div style=\"display: flex; flex-direction: column; gap: 10px;\">\r\n                  <input type=\"file\" id=\"input-backup-file-select\" accept=\".enc\" style=\"display: none;\" />\r\n                  <button id=\"btn-trigger-backup-file\" class=\"shortcut-reset-btn\" style=\"width: 100%; padding: 10px; font-size: 13px; border: 1px dashed var(--accent);\">📁 اختر ملف النسخة الاحتياطية (.enc)</button>\r\n                  <div id=\"lbl-backup-file-name\" style=\"font-size: 12.5px; color: var(--text-muted); text-align: center; display: none; margin-top: 5px;\"></div>\r\n                  <input type=\"password\" id=\"input-backup-import-password\" placeholder=\"أدخل كلمة المرور لفك التشفير...\" style=\"width: 100%; padding: 8px 12px; font-size: 13px; border-radius: 6px; background: var(--surface-2); border: 1px solid var(--border); color: var(--text);\" />\r\n                  <button id=\"btn-import-backup\" class=\"btn-activate-key\" style=\"width: 100%; padding: 10px; font-weight: bold; background: var(--success); color: white;\">فك تشفير واستيراد...</button>\r\n                </div>\r\n              </div>\r\n\r\n              <!-- مفتش العناصر -->\r\n              <div class=\"card\" style=\"background: rgba(255,255,255,0.02); padding: 16px; border: 1px solid var(--border); border-radius: 8px;\">\r\n                <h4 style=\"margin-bottom: 8px; display: flex; align-items: center; gap: 8px;\">🔍 مفتش العناصر ( UI Element Picker )</h4>\r\n                <p style=\"font-size: 12.5px; color: var(--text-muted); margin-bottom: 12px;\">أداة تفاعلية تتيح لك النقر على أي عنصر داخل واجهة التطبيق وتظليله والحصول على معرّفه الفرعي ( CSS Selector ) لنسخه مباشرة.</p>\r\n                <button id=\"btn-activate-picker\" class=\"shortcut-reset-btn\" style=\"width: 100%; padding: 10px; font-size: 13px; border: 1px dashed var(--accent); color: var(--accent); cursor: pointer;\">🔍 بدء تشغيل مفتش العناصر</button>\r\n              </div>\r\n\r\n              <!-- إعدادات وجهة الإدراج الذكي داخل التطبيق -->\r\n              <div class=\"card\" style=\"background: rgba(255,255,255,0.02); padding: 16px; border: 1px solid var(--border); border-radius: 8px;\">\r\n                <h4 style=\"margin-bottom: 8px; display: flex; align-items: center; gap: 8px;\">🎯 وجهة الإدراج التلقائي داخل التطبيق</h4>\r\n                <p style=\"font-size: 12.5px; color: var(--text-muted); margin-bottom: 12px;\">حدد صندوق النصوص المستهدف لإدراج النصوص فور تسجيلها أو معالجتها داخل واجهة المساعد.</p>\r\n                <div style=\"display: flex; gap: 8px; align-items: center; margin-bottom: 10px;\">\r\n                  <input type=\"text\" id=\"input-target-insertion-selector\" readonly placeholder=\"الافتراضي: #result-text\" style=\"flex: 1; padding: 8px 12px; font-size: 13px; border-radius: 6px; background: var(--surface-2); border: 1px solid var(--border); color: var(--text);\" />\r\n                  <button id=\"btn-pick-insertion-target\" class=\"btn-activate-key\" style=\"padding: 8px 12px; font-size: 12px; white-space: nowrap;\">تعيين بالالتقاط 🔍</button>\r\n                </div>\r\n                <button id=\"btn-reset-insertion-target\" class=\"shortcut-reset-btn\" style=\"width: 100%; padding: 6px; font-size: 12px;\">إعادة التعيين للافتراضي</button>\r\n              </div>\r\n            </div>\r\n          </div>\r\n            </div>\r\n          </div>\r\n        </section>\r\n";
